class Solution {
    public long minSumSquareDiff(int[] nums1, int[] nums2, int k1, int k2) {
        long res = 0;
        for (int i = 0; i < nums1.length; i++) {
            int diff = Math.abs(nums1[i] - nums2[i]);
            if (k1 + k2 >= diff) {
                k1 -= diff;
                k2 -= diff;
            } else {
                int d = Math.min(k1, k2);
                diff -= d;
                k1 -= d;
                k2 -= d;
                res += (long) diff * diff;
            }
        }
        res += (long) k1 * k1 + (long) k2 * k2;
        return res;
    }
}
